import { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../utils/api';
import { prefetch } from '../utils/prefetch';

// No hardcoded bots — users only see bots they've configured

function mapBotData(bot) {
  const eq = typeof bot.equity === 'object' ? bot.equity?.current : bot.equity;
  const unrealizedPnl = bot.unrealizedPnl ?? (typeof bot.equity === 'object' ? bot.equity?.unrealized_pnl : 0) ?? 0;
  const dayPnl = bot.dayPnl ?? bot.day_pnl ?? (typeof bot.equity === 'object' ? (bot.equity?.day_pnl ?? bot.equity?.day) : 0) ?? 0;
  const weekPnl = bot.weekPnl ?? bot.week_pnl ?? (typeof bot.equity === 'object' ? bot.equity?.week : 0) ?? 0;
  const monthPnl = bot.monthPnl ?? bot.month_pnl ?? (typeof bot.equity === 'object' ? bot.equity?.month : 0) ?? 0;
  return {
    name: (bot.display_name || bot.name || bot.bot_name || 'Unknown').toUpperCase(),
    bot_name: bot.bot_name || (bot.name || '').toLowerCase(),
    mode: bot.mode || 'unknown',
    enabled: bot.enabled ?? true,
    equity: eq || 0,
    dayPnl,
    weekPnl,
    monthPnl,
    pnl: { day: dayPnl, week: weekPnl, month: monthPnl },
    strategies: bot.strategies || [],
    trades: typeof bot.trades === 'number' ? bot.trades : (typeof bot.trade_count === 'number' ? bot.trade_count : (Array.isArray(bot.trades) ? bot.trades.length : 0)),
    positions: typeof bot.positions === 'number' ? bot.positions : (typeof bot.position_count === 'number' ? bot.position_count : (Array.isArray(bot.positions) ? bot.positions.length : 0)),
    clientId: bot.clientId || bot.client_id || null,
    lastHeartbeat: bot.lastHeartbeat || bot.last_heartbeat || null,
    status: bot.status || 'OK',
    connected: bot.status === 'OK' || bot.status === 'LIVE',
    strategy: Array.isArray(bot.strategies) && bot.strategies.length > 0
      ? bot.strategies.join(', ') : null,
    equityCurve: bot.equityCurve || [],
    buyingPower: bot.buyingPower || bot.buying_power || (typeof bot.equity === 'object' ? bot.equity?.buying_power : 0) || 0,
    color: bot.color || '#60A5FA',
    engine: bot.engine || null,
  };
}

import { PAPER_BOTS, BOT_METADATA_KEYS } from '../utils/constants';

// PAPER_BOTS and BOT_METADATA_KEYS imported from constants

function parseBots(data) {
  if (!data) return null;
  if (Array.isArray(data)) return data;
  if (data.bots && Array.isArray(data.bots)) return data.bots;
  if (data.bots && typeof data.bots === 'object') {
    return Object.entries(data.bots)
      .filter(([name, info]) => !BOT_METADATA_KEYS.has(name) && !PAPER_BOTS.has(name.toLowerCase()) && info && typeof info === 'object' && !Array.isArray(info))
      .map(([name, info]) => ({
        name: name.toUpperCase(),
        bot_name: name,
        mode: info?.payload?.mode || info?.mode || 'LIVE',
        enabled: info?.payload?.enabled ?? true,
        equity: info?.payload?.equity?.current ?? info?.equity?.current ?? 0,
        dayPnl: info?.payload?.equity?.day_pnl ?? info?.payload?.equity?.day ?? 0,
        weekPnl: info?.payload?.equity?.week ?? 0,
        monthPnl: info?.payload?.equity?.month ?? 0,
        unrealizedPnl: info?.payload?.equity?.unrealized_pnl ?? 0,
        strategies: [],
        trades: info?.payload?.trades?.length || 0,
        positions: info?.payload?.positions?.length || 0,
        clientId: info?.payload?.targets?.trading_client_id || null,
        lastHeartbeat: info?.last_heartbeat || null,
        status: info?.status || 'OK',
      }));
  }
  return null;
}

export default function useLiveBots() {
  // Seed from prefetch cache for instant first render
  const cachedBots = prefetch.get('bots');
  const [bots, setBots] = useState(() => {
    if (cachedBots) {
      const parsed = parseBots(cachedBots);
      return parsed ? parsed.map(mapBotData) : [];
    }
    return [];
  });
  const [apiLive, setApiLive] = useState(!!cachedBots);
  const cachedEqHist = prefetch.get('equityHistory');
  const [equityHistory, setEquityHistory] = useState(cachedEqHist || {});
  const eqHistRef = useRef(cachedEqHist || {}); // ref to avoid stale closure in fetchBots

  // Fetch equity history separately — slow cadence (60s)
  const fetchEquityHistory = useCallback(async () => {
    try {
      const eqData = await api('/telemetry/equity-history', { silent: true });
      if (eqData && typeof eqData === 'object' && !eqData.error) {
        setEquityHistory(eqData);
        eqHistRef.current = eqData;
      }
    } catch (e) {
      // Silently ignore — equity history is non-critical
    }
  }, []);

  // Fetch bots + telemetry — fast cadence (10s)
  const fetchBots = useCallback(async () => {
    let botsData, telData;
    try {
      [botsData, telData] = await Promise.all([
        api('/bots', { silent: true }).catch(() => null),
        api('/telemetry/latest', { silent: true }).catch(() => null),
      ]);
    } catch (e) {
      return; // API unreachable — keep last known state
    }

    const eqHist = eqHistRef.current;

    if (Array.isArray(botsData?.bots) && botsData.bots.length > 0) {
      const liveBots = botsData.bots.filter(b => !PAPER_BOTS.has((b.bot_name || '').toLowerCase()));
      const telBots = telData?.bots || {};
      const gwAccounts = telData?.gateway || {};
      const gwByClientId = {};
      Object.entries(gwAccounts).forEach(([key, val]) => {
        if (val && typeof val === 'object' && val.account) gwByClientId[val.account] = val;
      });

      const merged = liveBots.map(bot => {
        const tel = telBots[bot.bot_name] || {};
        const payload = tel.payload || {};
        const eq = payload.equity || bot.equity || {};
        // Match gateway by IBKR account ID (from targets or bot config) — NOT position overlap
        // Position overlap is unreliable when multiple accounts hold the same symbols
        const targets = payload.targets || {};
        const botAcctId = targets.account || bot.ibkr_account_id;
        const gw = (botAcctId ? gwByClientId[botAcctId] : null) || {};
        const gwEq = gw.equity || {};

        const rawHistoryPoints = eqHist[bot.bot_name] || [];
        const historyPoints = rawHistoryPoints.filter(p => p.equity != null && isFinite(p.equity));
        const curve = historyPoints.map(p => ({ ts: p.ts, value: p.equity }));
        const latestEq = historyPoints.length > 0 ? historyPoints[historyPoints.length - 1].equity : 0;

        // Backend enrichment already merges gateway NLV/P&L — trust eq.current
        const equityCurrent = (typeof eq === 'object' ? (eq.current ?? 0) : (eq ?? 0)) || gw.net_liquidation || latestEq;

        // Backend _enrich_bot_pnl now uses gateway P&L as highest priority
        // Trust the backend values directly — don't re-match gateway here
        const unrealizedPnl = typeof eq === 'object' ? (eq.unrealized_pnl ?? 0) : 0;
        const dayPnl = typeof eq === 'object' ? (eq.day_pnl ?? eq.day ?? 0) : 0;
        const weekPnl = typeof eq === 'object' ? (eq.week_pnl ?? eq.week ?? 0) : 0;
        const monthPnl = typeof eq === 'object' ? (eq.month ?? 0) : 0;

        return {
          ...bot,
          name: (bot.display_name || bot.bot_name || 'UNKNOWN').toUpperCase(),
          status: tel.status || bot.status || 'UNKNOWN',
          lastHeartbeat: tel.last_heartbeat || bot.last_heartbeat || null,
          equity: equityCurrent,
          dayPnl,
          weekPnl,
          monthPnl,
          unrealizedPnl,
          buyingPower: (typeof eq === 'object' ? (eq.buying_power ?? 0) : 0) || gwEq.buying_power || gwEq.available_funds || 0,
          positions: payload.positions?.length ?? bot.position_count ?? 0,
          trades: payload.trades?.length ?? bot.trade_count ?? 0,
          equityCurve: curve,
        };
      });
      setBots(merged.map(mapBotData));
      setApiLive(true);
      return;
    }

    // Fallback: telemetry-only (when /api/bots fails due to auth or network)
    const parsed = parseBots(telData);
    if (parsed && parsed.length > 0) {
      // Build gateway lookup for equity enrichment
      const gwAccounts = telData?.gateway || {};
      const gwByClientId = {};
      Object.entries(gwAccounts).forEach(([key, val]) => {
        if (val && typeof val === 'object' && val.account) gwByClientId[val.account] = val;
      });

      const withCurves = parsed.map(bot => {
        const botName = (bot.bot_name || bot.name || '').toLowerCase();
        const historyPoints = (eqHist[botName] || []).filter(p => p.equity != null && isFinite(p.equity));
        const curve = historyPoints.map(p => ({ ts: p.ts, value: p.equity }));
        const latestEq = historyPoints.length > 0 ? historyPoints[historyPoints.length - 1].equity : 0;

        // Backend _enrich_bot_pnl already merges gateway data into telemetry
        // Trust the backend values directly — don't re-match gateway by position overlap
        const telBotEq = telData?.bots?.[botName]?.payload?.equity || {};
        const equityCurrent = telBotEq.current || bot.equity || latestEq;
        const buyingPower = telBotEq.buying_power || telBotEq.available_funds || 0;

        return {
          ...bot,
          equity: equityCurrent,
          dayPnl: telBotEq.day_pnl ?? telBotEq.day ?? bot.dayPnl ?? 0,
          weekPnl: telBotEq.week_pnl ?? telBotEq.week ?? bot.weekPnl ?? 0,
          monthPnl: telBotEq.month ?? bot.monthPnl ?? 0,
          buyingPower,
          equityCurve: curve,
        };
      });
      setBots(withCurves.map(mapBotData));
      setApiLive(true);
    } else {
      setBots([]);
      setApiLive(false);
    }
  }, []);

  // Two independent polling loops — bots (30s), equity (90s)
  // Reduced from 10s/60s to cut API load by ~65%
  useEffect(() => {
    fetchEquityHistory();
    fetchBots();
    const eqInterval = setInterval(fetchEquityHistory, 90000);   // equity history every 90s
    const botInterval = setInterval(fetchBots, 30000);            // bot status every 30s
    return () => { clearInterval(eqInterval); clearInterval(botInterval); };
  }, [fetchEquityHistory, fetchBots]);

  return { bots, apiLive };
}
